#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int mod=998244353;

int n,p,k,ans,wk;

ll qpow(ll a,int b){
    a%=mod;
    if(a==0) return 0;
    ll ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int main(){
    scanf("%d%d%d",&n,&p,&k);
    wk=qpow(3,(mod-1)/k);
    for(int d=1,w=wk;d<k;d++,w=1ll*w*wk%mod)
        ans=(ans+(w*qpow(1ll*p*w+1,n)%mod-qpow(p+1,n))*qpow(w-1,mod-2)%mod)%mod;
    ans=(ans+1ll*n*p%mod*qpow(p+1,n-1)%mod+qpow(p+1,n))*qpow(k,mod-2)%mod;
    ans=(ans-qpow(p+1,n))%mod;
    printf("%d",(ans+mod)%mod);
    return 0;
}
